import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder rawBuilder = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            rawBuilder.append(line).append('\n');
        }
        // Replace escaped "\\n" with real newlines so tokenisation works for both formats
        String allInput = rawBuilder.toString().replace("\\\\n", "\n");
        Scanner sc = new Scanner(new StringReader(allInput));
        StringBuilder out = new StringBuilder();
        int T = sc.hasNextInt() ? sc.nextInt() : 0;
        for (int tc = 0; tc < T; tc++) {
            int N = sc.nextInt();
            int[] a = new int[N];
            for (int i = 0; i < N; i++) a[i] = sc.nextInt();
            List<int[]> ans = findTriplets(a);
            if (ans.isEmpty()) {
                out.append("-1");
            } else {
                for (int[] t : ans) {
                    out.append(t[0]).append(' ').append(t[1]).append(' ').append(t[2]).append('\n');
                }
                // remove trailing newline for this test case
                out.setLength(out.length() - 1);
            }
            if (tc != T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }

    private static List<int[]> findTriplets(int[] nums) {
        List<int[]> res = new ArrayList<>();
        int n = nums.length;
        if (n < 3) return res;
        Arrays.sort(nums);
        for (int i = 0; i < n - 2; i++) {
            if (i > 0 && nums[i] == nums[i - 1]) continue; // skip duplicate first element
            int l = i + 1, r = n - 1;
            while (l < r) {
                long sum = (long) nums[i] + nums[l] + nums[r];
                if (sum == 0) {
                    res.add(new int[]{nums[i], nums[l], nums[r]});
                    while (l < r && nums[l] == nums[l + 1]) l++;
                    while (l < r && nums[r] == nums[r - 1]) r--;
                    l++; r--;
                } else if (sum < 0) {
                    l++;
                } else {
                    r--;
                }
            }
        }
        return res;
    }
}

